forge solve(n) {
  2 * n - 1 -> multiplier
  n * multiplier -> result
  give result
}
emit solve(1)

forge solve(a, x) {
  0 -> count
  walk item across a {
    when item = x { count + 1 -> count }
  }
  give count
}
emit solve([1, 2, 3, 2, 1], 2)

forge solve(nums) {
  walk i across range(0, count(nums)) {
    nums @ i -> current
    walk j across range(0, count(nums)) {
      when j = i { skip }
      nums @ j -> other
      when current = other { give current }
    }
  }
  give -1
}
emit solve([1, 2, 3, 2, 4])

forge solve(nums) {
  walk k across nums {
    when k % 2 = 0 { give k }
  }
  give 0
}
emit solve([1, 2, 3, 4])

forge solve(list, element) {
  [] -> result
  walk item across list {
    push(result, element) -> result
    push(result, item) -> result
  }
  give result
}
emit solve([1, 2, 3], "x")

forge factorial(n) {
  1 -> result
  walk k across range(1, n + 1) {
    result * k -> result
  }
  give result
}

forge solve(n) {
  0 -> sum
  walk k across range(0, n + 1) {
    when k % 2 = 0 {
      factorial(n) -> f
      factorial(k) -> fk
      n - k -> nk
      factorial(nk) -> fnk
      f / (fk * fnk) -> coeff
      sum + coeff -> sum
    }
  }
  give sum
}

emit solve(4)

forge solve(list, element) {
  walk item across list {
    when item = element {
      yes -> checked
    } otherwise {
      give no
    }
  }
  give yes
}
emit solve(["apple", "apple", "apple"], "apple")

forge solve(arr, N, P) {
  0 -> count
  walk it across arr {
    it * it % P -> result
    when result = 1 { count + 1 -> count }
  }
  give count
}
emit solve([1, 2, 3, 4], 5, 5)

forge solve(a, b) {
  180 - a - b -> result
  give result
}
emit solve(60, 60)

forge solve(lst) {
  [] -> result
  walk item across lst {
    push(result, item @ 0) -> result
  }
  give result
}
emit solve([[1, 2], [3, 4], [5, 6]])

forge solve(nums, N) {
  [] -> result
  walk row across nums {
    row @ N -> element
    push(result, element) -> result
  }
  give result
}
emit solve([[1, 2, 3], [4, 5, 6], [7, 8, 9]], 1)

forge solve(n, m) {
  n % m -> result
  give result
}
emit solve(10, 3)

forge solve(b, h) {
  b * h -> result
  give result
}
emit solve(5, 3)

forge solve(b, s) {
  b * b + 2 * b * s -> result
  give result
}
emit solve(4, 3)

forge power(base, exp) {
  1 -> result
  walk _ across range(1, exp + 1) {
    result * base -> result
  }
  give result
}

forge solve(number) {
  number -> original
  0 -> sum
  sustain number > 0 {
    number % 10 -> digit
    3 -> exp
    power(digit, exp) -> contribution
    sum + contribution -> sum
    number / 10 -> number
  }
  give sum = original
}

emit solve(153)
